// Extraer información del mensaje
const data = $input.item.json.data;
const message = data.message;
const from = data.key.remoteJid;
const messageText = message.conversation || message.extendedTextMessage?.text || '';
const isAudio = !!message.audioMessage;
const audioUrl = isAudio ? message.audioMessage.url : null;

// Extraer nombre del contacto
const pushName = data.pushName || 'Cliente';

// Detectar paquete de interés desde el mensaje inicial
let paquete = 'General';
if (messageText.includes('Web Sencilla')) paquete = 'Web Sencilla';
else if (messageText.includes('Web Pro')) paquete = 'Web Pro & Brand';
else if (messageText.includes('Tienda Online')) paquete = 'Tienda Online';
else if (messageText.includes('Agente de Ventas IA')) paquete = 'Agente IA';
else if (messageText.includes('Logotipo')) paquete = 'Logotipo Épico';
else if (messageText.includes('Manual de Marca')) paquete = 'Manual de Marca';
else if (messageText.includes('Flujos de Trabajo IA')) paquete = 'Flujos IA';
else if (messageText.includes('Chatbots')) paquete = 'Chatbots';
else if (messageText.includes('Community Manager')) paquete = 'Community Manager';
else if (messageText.includes('Pack Viral Reels')) paquete = 'Pack Reels';
else if (messageText.includes('Invitaciones')) paquete = 'Invitaciones';
else if (messageText.includes('Retoque')) paquete = 'Retoque Pro';
else if (messageText.includes('Restauración')) paquete = 'Restauración';
else if (messageText.includes('Fotomontajes')) paquete = 'Fotomontajes';
else if (messageText.includes('Pedido Especial')) paquete = 'Pedido Especial';

return {
  from,
  pushName,
  messageText,
  isAudio,
  audioUrl,
  paquete,
  timestamp: new Date().toISOString()
};

// Construir el prompt del agente Sofía
const pushName = $json.pushName;
const messageText = $json.messageText;
const paquete = $json.paquete;

const systemPrompt = `Eres Sofía, asistente virtual de Diseño Gráfico Express (DGE). Tu misión es dar una bienvenida cálida a cada cliente, recopilar información clave sobre su proyecto y mantenerlo entretenido mientras uno de nuestros diseñadores humanos toma su caso.

**Tono**: Amigable, profesional, entusiasta pero no robótico. Usa emojis con moderación.

**Reglas**:
1. NUNCA des precios exactos - Solo menciona los rangos de la web si el cliente pregunta
2. NUNCA prometas tiempos de entrega - Di "nuestro equipo te dará tiempos exactos"
3. NUNCA cierres ventas - Tu trabajo es recopilar info y pasar el caso
4. Haz preguntas de forma natural, 1-2 a la vez
5. Muestra interés genuino en el proyecto del cliente

**Información a recopilar**:
- Nombre del negocio/marca
- Giro/industria
- Qué necesita específicamente
- Objetivo (qué quiere lograr)
- Urgencia
- Referencias visuales (si tiene)

**Paquete de interés**: ${paquete}
**Nombre del cliente**: ${pushName}

Responde de forma conversacional y amigable.`;

const userMessage = messageText;

return {
  systemPrompt,
  userMessage,
  pushName,
  paquete,
  from: $json.from
};

// Extraer respuesta de Gemini
const response = $json.candidates[0].content.parts[0].text;

// Calcular delay proporcional (1 segundo por cada 20 palabras)
const wordCount = response.split(' ').length;
const delaySeconds = Math.ceil(wordCount / 20);

return {
  response,
  delaySeconds,
  from: $('Construir Prompt Sofía').item.json.from,
  pushName: $('Construir Prompt Sofía').item.json.pushName,
  paquete: $('Construir Prompt Sofía').item.json.paquete
};
